using System.Collections;
using UnityEngine;

/// <summary>
/// Língua/puxão (Sapo "língua para puxar objectos leves ou alavancas";
/// canPullToSelf "puxar argolas" — P5). Ao usar (PrimaryAbility.TonguePull),
/// dispara um raycast frontal até "tongueRange" (P1) e, conforme o que acertar:
///
/// - Lever → Toggle (acciona a alavanca à distância);
/// - Switch → Activate;
/// - TongueAnchor (argola) → puxa o PLAYER até à argola;
/// - Rigidbody2D leve (ObjectWeight/Carryable até "maxPullWeight") → puxa o
///   OBJECTO até ao player a "tonguePullSpeed".
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class TonguePullAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Alvos")]
    [Tooltip("Peso máximo (ObjectWeight/rb.mass) de objectos puxáveis pela língua.")]
    public float maxPullWeight = 2f;

    [Tooltip("Camadas atingíveis pela língua. Vazio = todas.")]
    public LayerMask hitMask = ~0;

    [Tooltip("Distância ao alvo considerada 'chegou' (pára o puxão).")]
    public float arriveDistance = 0.6f;

    [Tooltip("Duração máxima de um puxão, em segundos (segurança).")]
    public float maxPullTime = 1.5f;

    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    // Buffer NonAlloc reutilizável — evita alocação em TryPull.
    private static readonly RaycastHit2D[] _rayBuffer = new RaycastHit2D[8];

    private bool enabledForForm;
    private float range = 4f;
    private float pullSpeed = 10f;
    private Coroutine routine;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && (form.canPullToSelf || form.primaryAbility == PrimaryAbility.TonguePull);
        range = form != null ? Mathf.Max(0.5f, form.tongueRange) : 4f;
        pullSpeed = form != null ? Mathf.Max(1f, form.tonguePullSpeed) : 10f;

        StopPull();
    }

    /// <summary>Usa a língua (AbilityRouter — PrimaryAbility.TonguePull).</summary>
    public void TryPull()
    {
        if (!enabledForForm || routine != null) return;
        if (motor.MovementLocked) return;

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;
        int count = Physics2D.RaycastNonAlloc(transform.position, new Vector2(dir, 0f), _rayBuffer, range, hitMask);

        for (int i = 0; i < count; i++)
        {
            var hit = _rayBuffer[i];
            if (hit.collider == null || hit.collider.gameObject == gameObject) continue;

            // Alavancas/switches à distância.
            var lever = hit.collider.GetComponent<Lever>();
            if (lever != null) { lever.Toggle(); return; }

            var sw = hit.collider.GetComponent<Switch>();
            if (sw != null) { sw.Activate(); return; }

            // Argola: puxa o player até lá.
            var anchor = hit.collider.GetComponent<TongueAnchor>();
            if (anchor != null)
            {
                routine = StartCoroutine(PullSelfRoutine(anchor.transform.position));
                return;
            }

            // Objecto leve: puxa-o até ao player.
            var targetRb = hit.collider.attachedRigidbody;
            if (targetRb != null && GetPullWeight(hit.collider) <= maxPullWeight)
            {
                routine = StartCoroutine(PullObjectRoutine(targetRb));
                return;
            }

            // Qualquer outra coisa sólida bloqueia a língua.
            if (!hit.collider.isTrigger) return;
        }
    }

    private float GetPullWeight(Collider2D col)
    {
        var ow = col.GetComponent<ObjectWeight>();
        if (ow != null) return ow.weight;

        return col.attachedRigidbody != null ? col.attachedRigidbody.mass : float.MaxValue;
    }

    private IEnumerator PullObjectRoutine(Rigidbody2D target)
    {
        float elapsed = 0f;

        while (elapsed < maxPullTime && target != null)
        {
            Vector2 toSelf = (Vector2)transform.position - target.position;
            if (toSelf.magnitude <= arriveDistance) break;

            target.velocity = toSelf.normalized * pullSpeed;

            elapsed += Time.deltaTime;
            yield return null;
        }

        if (target != null) target.velocity = Vector2.zero;
        routine = null;
    }

    private IEnumerator PullSelfRoutine(Vector2 anchorPos)
    {
        float elapsed = 0f;
        float gravityBefore = rb.gravityScale;

        motor.SetMovementLocked(true, this);
        rb.gravityScale = 0f;

        while (elapsed < maxPullTime)
        {
            Vector2 toAnchor = anchorPos - (Vector2)transform.position;
            if (toAnchor.magnitude <= arriveDistance) break;

            rb.velocity = toAnchor.normalized * pullSpeed;

            elapsed += Time.deltaTime;
            yield return null;
        }

        rb.velocity = Vector2.zero;
        rb.gravityScale = gravityBefore;
        motor.SetMovementLocked(false, this);
        routine = null;
    }

    /// <summary>Interrompe qualquer puxão em curso (troca de forma, dano...).</summary>
    public void StopPull()
    {
        if (routine == null) return;

        StopCoroutine(routine);
        routine = null;

        rb.gravityScale = rb.gravityScale == 0f ? 1f : rb.gravityScale;
        motor.SetMovementLocked(false, this);
    }

    // ---- IAbility (item 8) ----
    void IAbility.Activate() => TryPull();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) => StopPull();
    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => routine != null;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    // Sem cooldown: a HUD não mostra indicador para esta habilidade.
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm && routine == null && !motor.MovementLocked;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
